var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"천장이 무너져서 생긴 잔해가 길을 막고 있습니다.","JPN":"天井が崩れ落ちてできた残骸が道を塞いでます。","ENG":"The debris from the collapse is blocking our way.","TWN":"天花板坍塌的殘骸擋住了去路。"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"이 앞은 살펴보기 어렵겠군요.","JPN":"この先を確かめるのは難しそうですね。","ENG":"It's going to be difficult trying to see what's on the other end.","TWN":"這前面沒辦法查看了呢。"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MAN_NPC_ESPR2_B","text":{"KOREA":"그, 그만 돌아가시죠. 부학회장님. 몸도 편찮으시다고 하던데…….","JPN":"も、もう戻りましょう。副学会長。お身体も本調子ではないと聞きましたし……","ENG":"L-let's go back, Vice President. I heard you are... not feeling well...","TWN":"我…我們回去吧，副學會長。聽說你身體也不好……"},"stage":{"bg":"UNDER","slots":{"L":{"char_id":"MAN_NPC_ESPR2_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAN_NPC_ESPR2_B","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"MAN_NPC_ESPR2_A","text":{"KOREA":"맞습니다. 설마 그 불손한 외지인이 이런 곳으로 숨어 들었으려고요.","JPN":"そうですよ。あの不遜なよそ者がこんなところに潜り込むとは思えません。","ENG":"I agree. There's no way that insolent outlander will hide somewhere like here.","TWN":"沒錯。那個不速之客，應該也不會躲到這種地方來。"},"stage":{"bg":"UNDER","slots":{"L":{"char_id":"MAN_NPC_ESPR2_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAN_NPC_ESPR2_B","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"콜록, 콜록……!","JPN":"ゲホ、ゲホ……！","ENG":"*Cough!* *Cough!*","TWN":"咳咳、咳咳……！"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아뇨. 사람이 지나간 흔적은 이 방향을 가리키고 있어요.","JPN":"いいえ。人が通った跡はこちらの方向を示しています。","ENG":"No, the tracks all point to here.","TWN":"不，這裡有人經過的痕跡。"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"이것 보세요. 탄창이 바닥에 떨어져 있잖아요? 정신없이 도망치다가 떨어뜨린 거겠죠.","JPN":"見てください。弾倉が床に落ちていますわ。あわてて逃げていて落としてしまったのでしょう。","ENG":"Look. See that empty magazine on the floor? It must've slipped out while he was running from us.","TWN":"看看這個。地面上有個彈匣不是嘛？應該是他慌亂逃跑時掉下來的吧。"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그리고 영지에 들어왔다던 그 외지인, 붙잡으면 해부학 실습용으로 쓸 생각 아니었나요?","JPN":"それに領地に入ったというその者、捕まえたら解剖学の実習に使うつもりだったのではありませんか？","ENG":"Also, weren't you planning on using that outlander's cadaver for anatomy practice?","TWN":"還有，你不是想抓到進入領地的那個外地人後，用於解剖學實習嗎？"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"그렇습니다. 허락 받지 않은 침입자의 처우는 현장에서 판단하는 것이 학회의 규정이기에.","JPN":"そのとおりです。無断侵入した者の処遇は現場で判断するのが学会のきまりですので。","ENG":"Yes. The Society's rules dictate that anyone who enters without permission is to have their fate decided upon capture.","TWN":"是的。未經允許的入侵者，可以在現場判斷如何處置，這是學會的規定。"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"길을 잃은 사람이면 곱게 돌려보내 줘야죠.","JPN":"道に迷った人であればちゃんと帰してあげるべきですわ。","ENG":"But let him go if he was lost and wandered in.","TWN":"如果是迷路的人，就應該好好地送他離開。"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"앞으로 영지에서 해부학 실습을 할 때는 합법적으로 제공되는 카데바를 사용하세요.","JPN":"これから領地で解剖学の実習をする場合は、合法的に提供された献体を使ってください。","ENG":"From now on, you are only allowed to use legally obtained cadavers for anatomy practices within the estate.","TWN":"以後在領地進行解剖學實習時，都要使用合法提供的屍體。"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"……예. 의학부에 전파하겠습니다.","JPN":"……承知しました。医学部に伝えておきます。","ENG":"...Yes, ma'am. I'll relay the message to the medical department.","TWN":"……是的，我會傳達給醫學院。"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"흐흥, 까탈스럽긴. 원래 들키지만 않으면 합법 아닐까?","JPN":"フフン、生真面目ね。バレなきゃ全部合法じゃないの？","ENG":"Hmph. Why so uptight? Also, it's not illegal if they don't catch you in the act, right?","TWN":"嗯哼，真苛刻啊。只要不被發現，就算是合法的吧？"},"stage":{"bg":"UNDER","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"쓸데없는 소리 말고 기름등 좀 들어 줘요.","JPN":"余計なことを言ってないで、ちょっとランタンを持っていてください。","ENG":"Stop your nonsense and hold the oil lamp for me.","TWN":"少廢話，快幫我提著油燈。"},"stage":{"bg":"UNDER","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"이럴 줄 알고 서재에서 지하 수로 설계도를 찾아 왔거든요.","JPN":"こういうこともあろうかと、書斎から地下水路の設計図を持ってきたのです。","ENG":"I brought the blueprints for the underground waterway from the study in case this would happen.","TWN":"我就知道會這樣，所以從書房找來了地下水道的設計圖。"},"stage":{"bg":"UNDER","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"지어진 지 수백 년은 된 것 같던데…… 어디……","JPN":"作られてから数百年は経過しているようですが……さて……","ENG":"Let me see here... It seems as if it has been built centuries ago...","TWN":"好像已經建成幾百年了……我看看……"},"stage":{"bg":"UNDER","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"우와, 완전 미로네. 길치인 사람은 평생 헤매다가 뼈만 남겠어.","JPN":"うわ、完全に迷路だね。方向音痴は一生彷徨って骨になっちゃいそう。","ENG":"Wow... It's like a maze. Anyone with a poor sense of direction will end up and a pile of bones here, don't you think?","TWN":"哇啊，這裡完全是個迷宮。如果是路癡的話，我看走到老死也走不出去吧。"},"stage":{"bg":"UNDER","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_SURPRISE"}}}}]`);export{e as default};